import java.util.Date;
import java.util.Objects;

public class TimeCode {
    public static final String TIME_PATTERN = "HH:mm:ss";

    private int offsetHours;
    private int offsetMinutes;
    private double seconds;
    private int minutes;
    private int hour;

    // Getters
    public int getOffsetHours() {
        return offsetHours;
    }

    public int getOffsetMinutes() {
        return offsetMinutes;
    }

    public double getSeconds() {
        return seconds;
    }

    public int getMinutes() {
        return minutes;
    }

    public int getHour() {
        return hour;
    }

    // Setters
    public void setOffsetHours(int offsetHours) {
        this.offsetHours = offsetHours;
    }

    public void setOffsetMinutes(int offsetMinutes) {
        this.offsetMinutes = offsetMinutes;
    }

    public void setSeconds(double seconds) {
        this.seconds = seconds;
    }

    public void setMinutes(int minutes) {
        this.minutes = minutes;
    }

    public void setHour(int hour) {
        this.hour = hour;
    }

    // Other operations
    public long getMilliseconds() {
        double totalSeconds = hour * 3600.0 + minutes * 60.0 + seconds;
        return Math.round(totalSeconds * 1000.0);
    }

    public void setTime(long milliseconds) {
        long totalSeconds = milliseconds / 1000;
        long ms = milliseconds % 1000;

        hour = (int) ((totalSeconds / 3600) % 24);
        minutes = (int) ((totalSeconds % 3600) / 60);
        seconds = (totalSeconds % 60) + ms / 1000.0;
    }

    public Date toDate() {
        return new Date(getMilliseconds());
    }

    public String toISO8601() {
        // hours:minutes:seconds[.fraction] with offset
        int secInt = (int) Math.floor(seconds);
        double frac = seconds - secInt;
        String secStr;
        if (frac > 0) {
            secStr = String.format("%02d.%03d", secInt, (int) Math.round(frac * 1000));
        } else {
            secStr = String.format("%02d", secInt);
        }

        String offset = String.format("%c%02d:%02d",
                (offsetHours < 0 || offsetMinutes < 0) ? '-' : '+',
                Math.abs(offsetHours),
                Math.abs(offsetMinutes)
        );

        return String.format("%02d:%02d:%s%s", hour, minutes, secStr, offset);
    }

    @Override
    public String toString() {
        return "TimeCode{hour=" + hour +
                ", minutes=" + minutes +
                ", seconds=" + seconds +
                ", offsetHours=" + offsetHours +
                ", offsetMinutes=" + offsetMinutes +
                "}";
    }

    @Override
    public int hashCode() {
        return Objects.hash(hour, minutes, seconds, offsetHours, offsetMinutes);
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (obj == null || getClass() != obj.getClass()) return false;
        TimeCode other = (TimeCode) obj;
        return hour == other.hour &&
                minutes == other.minutes &&
                Double.doubleToLongBits(seconds) == Double.doubleToLongBits(other.seconds) &&
                offsetHours == other.offsetHours &&
                offsetMinutes == other.offsetMinutes;
    }
}
